fn solve(points: Vec<Vec<i64>>) -> i64 {
    use std::collections::HashMap;

    let mut y_map: HashMap<i64, Vec<i64>> = HashMap::new();
    for point in points.iter() {
        let x = point[0];
        let y = point[1];
        y_map.entry(y).or_default().push(x);
    }

    let mut count = 0;
    let mod_val = 1_000_000_007;

    // Collect y-coordinates with at least two points to form horizontal lines
    let y_coords: Vec<_> = y_map.iter()
        .filter(|(_, xs)| xs.len() >= 2)
        .map(|(&y, _)| y)
        .collect();

    for i in 0..y_coords.len() {
        for j in i+1..y_coords.len() {
            let y1 = y_coords[i];
            let y2 = y_coords[j];
            let xs1 = y_map.get(&y1).unwrap();
            let xs2 = y_map.get(&y2).unwrap();

            // Sort the x-coordinates for both y-lines
            let mut sorted_xs1 = xs1.clone();
            sorted_xs1.sort_unstable();
            let mut sorted_xs2 = xs2.clone();
            sorted_xs2.sort_unstable();

            // Find all possible pairs of x-coordinates in both lines
            let m = sorted_xs1.len();
            let n = sorted_xs2.len();
            let mut k = 0;
            let mut l = 0;
            let mut pairs = 0;

            while k < m && l < n {
                if sorted_xs1[k] == sorted_xs2[l] {
                    pairs += 1;
                    k += 1;
                    l += 1;
                } else if sorted_xs1[k] < sorted_xs2[l] {
                    k += 1;
                } else {
                    l += 1;
                }
            }

            // The number of ways to choose two distinct pairs is C(a, 2) * C(b, 2)
            let a = sorted_xs1.len() - pairs;
            let b = sorted_xs2.len() - pairs;
            let c = pairs;
            let ways = (a * b) as i64 + (c * (c - 1) / 2) as i64;
            count = (count + ways) % mod_val;
        }
    }

    count
}
