    let mut y_map: HashMap<i64, Vec<i64>> = HashMap::new();
    for point in points.iter() {
        let x = point[0];
        let y = point[1];
        y_map.entry(y).or_default().push(x);
    }

    let mut count = 0;
    let mod_val = 1_000_000_007;

    // Collect y values with at least two points to form horizontal lines
    let y_values: Vec<_> = y_map.iter()
        .filter(|(_, xs)| xs.len() >= 2)
        .collect();

    for i in 0..y_values.len() {
        let (y1, xs1) = y_values[i];
        let xs1_sorted = {
            let mut v = xs1.clone();
            v.sort();
            v
        };
        let n1 = xs1_sorted.len();

        for j in i+1..y_values.len() {
            let (y2, xs2) = y_values[j];
            let xs2_sorted = {
                let mut v = xs2.clone();
                v.sort();
                v
            };
            let n2 = xs2_sorted.len();

            // Find pairs of x coordinates that are common between the two y lines
            let mut common_pairs = 0;
            let mut left = 0;
            let mut right = 0;
            let mut prev_x = None;

            while left < n1 && right < n2 {
                if xs1_sorted[left] == xs2_sorted[right] {
                    if prev_x.is_none() || prev_x.unwrap() != xs1_sorted[left] {
                        common_pairs += 1;
                        prev_x = Some(xs1_sorted[left]);
                    }
                    left += 1;
                    right += 1;
                } else if xs1_sorted[left] < xs2_sorted[right] {
                    left += 1;
                } else {
                    right += 1;
                }
            }

            // The number of trapezoids is C(n1, 2) * C(n2, 2) - C(common_pairs, 2)
            let c_n1 = n1 as i64 * (n1 as i64 - 1) / 2;
            let c_n2 = n2 as i64 * (n2 as i64 - 1) / 2;
            let c_common = common_pairs * (common_pairs - 1) / 2;
            count = (count + c_n1 * c_n2 - c_common) % mod_val;
        }
    }

